document.addEventListener("DOMContentLoaded",function(){const t=document.querySelectorAll(".jc-cat-list");t.forEach(t=>{t.addEventListener("click",function(t){const e=t.target.closest(".jc-cat-list__toggle");if(!e)return;t.preventDefault(),t.stopPropagation();const n=e.closest(".jc-cat-list__item");if(n){const t=n.classList.contains("is-expanded");n.classList.toggle("is-expanded"),e.setAttribute("aria-expanded",!t)}})})});